var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리드웬 기관</color> 비밀 격리 시설 LAKE-4 ","JPN":"<color=#ffd34c>プリドウェン機関</color>の秘密隔離施設 LAKE-4 ","ENG":"<color=#ffd34c>Prydwen Institution</color> Secret Quarantine Facility LAKE-4","TWN":"<color=#ffd34c>普利多溫機關</color>秘密隔離設施LAKE-4"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 <color=#ffd34c>최고등급 재난경보</color> 발령 후 3시간 뒤","JPN":"管理局<color=#ffd34c>最高ランクの災難警報</color>発令から3時間後","ENG":"3 hours after the Administration issuing the <color=#ffd34c>highest-level disaster alert</color>","TWN":"管理局發佈<color=#ffd34c>最高級災難警報</color>3小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"제길, 이곳의 수복이 아직 완전히 끝나지도 않았는데, 최고등급 재난 경보라니…….","JPN":"くそ、ここの修復がまだ完全に終わってないのに、最高ランクの災難警報とは……","ENG":"Bollocks, we haven't even fully recovered this area, and now a highest-level disaster alert...?","TWN":"可惡，這裡的收復工作還沒完全結束，就發佈了最高級別的災難警報……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"그야말로 설상가상이로군.","JPN":"弱り目に祟り目ってまさにこれだな。","ENG":"It's only gotten worse.","TWN":"真是雪上加霜。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"전 인원, 복구 작업을 중단하고 모두 레벨 3 이상의 CSE 방호복을 착용해!","JPN":"総員、復旧作業を中断してみんなレベル3以上のCSE防護服を着用しろ！","ENG":"All units are to stop the restoration work and put on protective suits of CSE levels 3 and higher!","TWN":"全體人員，停止收復工作，全部穿上3級以上CSE防護服！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"시설에 봉인된 파편이 눈보라에 노출되지 않도록 방재 작업을 최우선으로 수행한다!","JPN":"施設に封印された破片が吹雪に晒されないよう、防災作業を最優先に遂行する！","ENG":"Prioritise disaster prevention, so that the Fragment sealed within the facility aren't exposed to the snowstorm!","TWN":"優先做好防災工作，確保封印在設施的碎片不會暴露在暴風雪下！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"프레임에 고정된 봉인 사슬을 보호해! 방수포라도 덮어 놔!","JPN":"フレームに固定された封印の鎖を保護しろ！　防水布でも被せておけ！","ENG":"Protect the Sealing Chains fixed to the frame! Cover it with a waterproof tarp or something!","TWN":"保護固定在邊框上的封印鎖鏈！把防水布蓋上！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"지휘관님! 학회 녀석들이 시설을 습격했습니다!","JPN":"指揮官！　学会のやつらが施設を襲撃しました！","ENG":"Commander! The Society bastards are attacking the facility!","TWN":"指揮官！學會的傢伙正在襲擊設施！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"뭐, 뭐라고!?","JPN":"な、何だと！？","ENG":"W-what?!","TWN":"什，什麼？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"이곳뿐만이 아닙니다. 다른 봉인 시설에서도 동시에 보고가 들어왔습니다!","JPN":"ここだけではありません。他の封印施設からも同様の報告が来ています！","ENG":"Not just this one. We've received simultaneous reports from the other quarantine facilities as well!","TWN":"不光是這裡，其他封印設施也同時發來了遇襲報告！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"녀석들을 막아!","JPN":"やつらを止めろ！","ENG":"Stop them!","TWN":"攔住他們！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"어차피 학회에서도 버려진 떨거지들일 뿐이다!","JPN":"どうせ学会からも見捨てられた落ちこぼれだ！","ENG":"They're nothing but failures that were abandoned by the Society!","TWN":"他們只是被學會拋棄的嘍囉而已！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"중대장님! 이터니움 실드의 소모량이 너무 빠릅니다!","JPN":"中隊長！　エタニウムシールドの消耗が激しいです！","ENG":"Sir! The Eternium shield is rapidly decaying!","TWN":"中隊長！永恆之金盾的消耗太快了！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"습격한 적들의 편성은 대다수가 애콜라이트와 잔해입니다.","JPN":"襲撃した敵の編成は、ほとんどがアコライトと残骸です。","ENG":"The enemies consist mostly of Acolytes and Remains.","TWN":"襲擊的敵人大多數是輔祭和殘骸。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"고위 침식파장에도 끄떡없어요!","JPN":"高レベルの侵食波長にもビクともしません！","ENG":"The high-grade Corruption ray isn't doing anything to them!","TWN":"連高級侵蝕波也拿他們沒辦法！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"이대로 가다간…… 싸우기도 전에 다들 미쳐버릴 겁니다!","JPN":"このままでは……戦う前にみんなおかしくなってしまいます！","ENG":"At this rate... we're all going to be driven mad before we even get a chance to fight!","TWN":"照這樣下去……還沒打起來，大家就會瘋掉！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"제길! D-7 구역까지 후퇴한 뒤, 그곳에서 이터니움을 충전하고 방어전을 전개한다.","JPN":"くそ！　D-7区域まで撤退し、そこでエタニウムを充電して防御戦を展開する。","ENG":"Bloody hell! We retreat to area D-7, charge Eternium, and switch to defensive combat.","TWN":"該死！撤退到D-7區域後，在那裡補充永恆之金，然後展開防禦戰。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"이곳을 두 번 잃을 수는 없어!","JPN":"二度もここを失うわけにはいかない！","ENG":"We can't lose this place again!","TWN":"這個地方不能再丟第二次了！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"기관장님의 명령이 있을 때까지 무슨 일이 있어도 버텨야 한다!","JPN":"機関長の命令があるまで、何があって耐えしのげ！","ENG":"We cannot fall before we receive any orders from the Chief!","TWN":"不管發生什麼事，都要堅持到機關長下達命令！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"기관 녀석들이 물러나고 있다! 서둘러!","JPN":"機関のやつらが押されているぞ！　急げ！","ENG":"The Institution pricks are falling back! Hurry!","TWN":"機關的傢伙們正在撤退！快點！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L43_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"이곳을 점령하고 파편을 회수한다!","JPN":"ここを占領して破片を回収する！","ENG":"Capture the area and retrieve the Fragment!","TWN":"我們要佔領這裡，回收碎片！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"모든 것은 지식의 호수가 하나가 되기 위해서!","JPN":"すべては、知識の湖が一つになるため！","ENG":"For the Lake of Knowledge to become one!","TWN":"一切都是為了讓知識湖水合而為一！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"同時間"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리드웬 기관 본부</color> 라운드 테이블","JPN":"<color=#ffd34c>プリドウェン機関本部</color>ラウンドテーブル","ENG":"<color=#ffd34c>Prydwen Institution HQ</color> Round Table","TWN":"<color=#ffd34c>普利多溫機關總部</color>圓桌會議"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"기관장님! 페리어 요원님이 중상을 입으셨습니다!","JPN":"機関長！　フェリエー様が重傷です！","ENG":"Chief! Agent Ferrier has been gravely injured!","TWN":"機關長！佩里特工受了重傷！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"다른 기관원들도 부상이 심각합니다!","JPN":"他の機関員たちも大怪我を負っています！","ENG":"The other members are in a dire state as well!","TWN":"其他機關成員的傷勢也很嚴重！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"즉시, 구조팀을 보낼 테니 안심하세요. 상황은 어떻게 되었죠?","JPN":"直ちに、救助チームを送るので安心してください。状況はどうですか？","ENG":"Don't worry, I'll send a rescue team this instant. What's the situation?","TWN":"請放心，我會馬上派救援隊過去。現在情況怎麼樣？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"제임스 고고학부장은 놓쳤습니다. 즉시 추적팀을 편성해야 합니다.","JPN":"ジェームス考古学部長は逃走しました。すぐに追跡チームを編成するべきです。","ENG":"We lost the Dean of Archeology. We must form a team to go after him immediately.","TWN":"我們沒能抓到詹姆斯考古學教授，目前需要立刻組成追擊隊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"행선지는 파악했나요?","JPN":"逃げた先は把握できたのですか？","ENG":"Have you figured out where he's headed?","TWN":"知道去哪裡嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"선박에 부착한 발신기의 마지막 위치를 따져보면, 성황청으로 밀항하려는 것 같습니다.","JPN":"船舶に取り付けた発信機の最後の位置から推測するに、聖皇庁に密航する模様です。","ENG":"Based on the last location of the transmitter we attached to the ship, it seems like he is attempting to smuggle himself into the Holy Curia.","TWN":"從附著在船上的發信器的最後位置來看，似乎是想偷渡到聖皇廳。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇다면 역시 제임스의 목표는…….","JPN":"では、やはりジェームスの目的は……","ENG":"Then James is after...","TWN":"那麼，詹姆斯的目標是……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"조심하십시오, 기관장님.","JPN":"お気を付けください、機関長。","ENG":"Be cautious, Chief.","TWN":"請你小心，機關長。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"고고학부장의 탈옥을 도운 녀석들은 일반적인 학회 잔당과는 다릅니다.","JPN":"考古学部長の脱獄を手伝ったやつらは、一般的な学会の残党とはワケが違います。","ENG":"The ones who broke out the Dean of Archeology are different from the ordinary remnants of the Society.","TWN":"幫助考古學教授越獄的傢伙與一般的學會餘黨不同。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"녀석들은 자신들을 얄다바오트의 자녀들이라고 부르더군요.","JPN":"やつらは自分たちのことをヤルダバオトの子供だと言っていました。","ENG":"They call themselves the Children of Yaldabaoth.","TWN":"他們稱自己為亞達巴沃的子女。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"얄다바오트의 자녀들…….","JPN":"ヤルダバオトの子供……","ENG":"Children of Yaldabaoth...","TWN":"亞達巴沃的子女……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"스스로 반역자의 자녀를 자처하고 있군요.","JPN":"自分で反逆者の子孫を名乗っていますわね。","ENG":"They are claiming to be the children of a traitor.","TWN":"竟以叛徒的子女自居。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"알겠습니다. 구조팀이 올 때까지 라이언 요원의 응급조치를 부탁드리겠습니다.","JPN":"わかりました。救助チームが来るまで、エージェント・ライアンの応急措置をお願いします。","ENG":"Very well. Please take care of Agent Ryan until the rescue team arrives.","TWN":"我知道了，在救援隊到來之前，請對瑞安特工採取搶救措施。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"LAKE-4, LAKE-7, LAKE-11…….","JPN":"LAKE-4、LAKE-7、LAKE-11……","ENG":"LAKE-4, LAKE-7, LAKE-11...","TWN":"LAKE-4，LAKE-7，LAKE-11……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"관리국 최고등급 재난경보를 틈타, 현재 비밀 격리 시설이 일제히 공격받고 있습니다.","JPN":"管理局最高ランクの災難警報に付け入り、現在秘密隔離施設が一斉攻撃されていますわ。","ENG":"The enemy took advantage of the Administration's highest-level disaster alert and are attacking all the secret quarantine facilities.","TWN":"在管理局發佈最高級災難警報之際，秘密隔離設施都受到了攻擊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"동시에 적은 왕립교정국을 공격해, 제임스 고고학부장의 탈옥을 성공시켰죠.","JPN":"それと同時に敵は王立矯正局を攻撃し、ジェームス考古学部長の脱獄を成功させました。","ENG":"At the same time, they attacked the Royal Correctional Service and broke out the Dean of Archeology.","TWN":"同時敵人還攻打了王室矯正局，並成功幫助考古學教授詹姆斯越獄。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"비밀 격리 시설의 파편이 우선인지, 고고학부장의 추적이 우선인지…….","JPN":"秘密隔離施設の破片を優先するべきか、考古学部長の追跡を優先するべきか……","ENG":"Do we prioritise the Fragment in the secret quarantine facility or tracking the Dean of Archeology...?","TWN":"是秘密隔離設施的碎片優先，還是追捕考古學教授優先……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관은 또 다시 선택의 기로에 놓이게 되었군요.","JPN":"機関はまた選択の岐路に立つことになりましたわね。","ENG":"The Institution is once again at a crossroads.","TWN":"機關又重新站在了選擇的十字路口。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자고로 퀸은 그리 쉽게 움직여서는 안 되는 법이지요.","JPN":"本来、クイーンはそう容易く動いてはいけないものです。","ENG":"However, the queen should not move carelessly.","TWN":"自古以來，皇后就不應該輕易移動。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"제임스의 꽁무니를 쫓는 건, 저와 버넷 요원이 페어가 되어서 수행하도록 하겠습니다.","JPN":"ジェームスを追うのは俺とエージェント・バーネットのペアで遂行しましょう。","ENG":"Agent Burnett and I will work as a pair and track down James.","TWN":"追捕詹姆斯的任務，就由我和伯內特特工負責。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨께서는 본부에서 격리 시설의 지휘를 맡아 주시죠.","JPN":"お嬢様は本部で隔離施設の指揮を担当してください。","ENG":"You should command the quarantine facility from HQ.","TWN":"小姐，請你在總部負責指揮隔離設施的作戰。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제임스 고고학부장과는 개인적인 원한 관계가 있는 것으로 알고 있습니다. 모건.","JPN":"ジェームス考古学部長に個人的な恨みがあることは承知の上で問いますわ。モーガン。","ENG":"Morgan, I'm aware that you have a personal grudge against the Dean of Archeology.","TWN":"據我所知，你與考古學教授詹姆斯有個人恩怨，摩根。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"임무에 사적인 감정을 품지 않으리라 자신할 수 있나요?","JPN":"任務に私的感情を持ち込まない自信はありますか？","ENG":"Are you sure your personal feelings won't be involved in this mission?","TWN":"你能保證你不會在任務中摻雜個人感情嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"후후, 죄송하지만 그건 자신할 수 없군요.","JPN":"ふふ、申し訳ありませんが、それは自信がありませんな。","ENG":"Hah hah. I'm afraid I cannot promise anything.","TWN":"呵呵，抱歉，那個我不敢保證。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 반대하겠습니다.","JPN":"では、私は反対です。","ENG":"Then I am against it.","TWN":"那我反對。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"격리 시설 방어에 초점을 맞춘 뒤, 재난경보가 해제되면 고고학부장을 추적합니다.","JPN":"今は隔離施設の防御に集中し、災難警報が解除されてから考古学部長を追跡しましょう。","ENG":"We will focus on defending the quarantine facility and will track down the Dean of Archeology after the disaster alert is lifted.","TWN":"先將重點放在隔離設施的防禦，等災難警報解除後再追捕考古學教授。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"새디어스 모건, 당신은 얌전히 회복에 전념하도록 하세요.","JPN":"タデウス・モーガン、あなたは大人しく回復に専念しなさい。","ENG":"Thaddeus Morgan, you are to prioritise your own recovery.","TWN":"薩迪烏斯·摩根，你就乖乖地專心休養吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"홍차 폭탄, 그럼 나는 뭘 하면 되는데?","JPN":"紅茶爆弾、じゃあ俺は何をすればいいんだ？","ENG":"What do I do, Tea Bomb?","TWN":"紅茶炸彈，那我需要做什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아무것도 하지 마세요. 정직 3개월이라고 했을 텐데요?","JPN":"何もしないでください。停職3か月と言ったはずですわ。","ENG":"Nothing. Haven't I told you that you are suspended for three months?","TWN":"什麼也不要做，我不是說了，你停職3個月嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"야! 지금 자존심 내세울 때야? 그러다가 교수를 영영 놓치면 어쩔 건데?","JPN":"おい！　今はそんなこと言ってる場合じゃないだろ！　これで永遠に教授を逃がすことになったらどうするんだよ。","ENG":"Oi! This isn't the time to put your petty pride first! What if you lose the Professor for good?","TWN":"喂！現在不是嘔氣的時候吧？如果這樣下去，永遠抓不到教授怎麼辦？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"페리어 요원이 당했습니다.","JPN":"エージェント・フェリエーがやられました。","ENG":"Agent Ferrier was taken down.","TWN":"佩里特工被攻擊了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"적의 규모도, 정체도 모르는데 당신 같은 반푼이를 최전선에 보낼 수는 없어요.","JPN":"敵の規模も正体もわからないのに、あなたのような半人前を最前線に送るわけにはいきません。","ENG":"We cannot send a muppet like you to the frontlines when we have no intel on the enemy's size or identity.","TWN":"我們甚至不清楚敵人的規模和來歷，所以不能把你這種傻瓜派到前線去。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨. 부디 저를 보내주십시오.","JPN":"お嬢様、どうか俺にご命令を。","ENG":"My lady. Please, allow me to take this task.","TWN":"請務必讓我去，小姐。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"늙은 사냥개가 오랫동안 쫓아온 숙적의 냄새를 맡고, 포기하리라 생각하셨습니까?","JPN":"老いた猟犬がずっと追って続けてきた宿敵の匂いを嗅ぎつけたのです。諦められると思いますか？","ENG":"Did you think an old hound like me could give up after catching the scent of an old nemesis?","TWN":"老獵犬已經聞到了追逐已久的宿敵的氣味。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"단언하죠.","JPN":"断言しましょう。","ENG":"I know this for sure.","TWN":"我敢肯定。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"형님께서 없는 지금, 그 일에 적임자는 저 이외에 아무도 없을 겁니다.","JPN":"バーネットのいない今、その仕事の適任者は俺しかいません。","ENG":"Without Sir Burnett, I am the only one fit for the task.","TWN":"沒有大哥的現在，除了我以外，沒有人能勝任這份工作了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하아. 그래서 그런 거라고요. 모건 아저씨…….","JPN":"はあ。だからですのよ。モーガンおじさま……","ENG":"*Sigh.* That's exactly why, Mr. Morgan...","TWN":"哀，所以我才會這麼決定，摩根叔叔……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 복수심이 당신마저 죽일 것 같아서.","JPN":"その復讐の炎があなたまで燃やしてしまいそうで。","ENG":"It's because I'm worried your vengeance is what is going to get you killed.","TWN":"我怕那個復仇心會害死你。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"좋습니다. 새디어스 모건. 대신 한 가지 약속해주세요.","JPN":"いいでしょう。タデウス・モーガン。その代わりに、一つだけ約束してください。","ENG":"Very well, Thaddeus Morgan. However, you must promise me one thing.","TWN":"好吧，薩迪烏斯·摩根。但是請答應我一件事。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"은퇴 전까지 당신의 목숨은 기관의 자산입니다.","JPN":"引退するまでは、あなたの命は機関の資産です。","ENG":"Your life is the property of the Institution until the day you retire.","TWN":"直到退休前，你的生命是機關的寶貴財產。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 반드시 살아서 돌아오세요.","JPN":"ですので、必ず生きて帰ってきなさい。","ENG":"So, make it out alive.","TWN":"所以一定要活著回來。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"살아서…… 우리가 당신의 헌사에 보답할 수 있도록, 평온한 여생을 보내주세요.","JPN":"生きて……私たちがあなたの働きに恩返しできるよう、平和な余生を過ごしてください。","ENG":"Stay alive... and spend the rest of your days in peace, so that we can compensate you for your hard work.","TWN":"活著……度過平靜的餘生，好讓我們來報答你的奉獻。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아시겠어요, 이 고집불통?","JPN":"いいですわね？　この頑固者。","ENG":"Do you understand, you stubborn old man?","TWN":"知道了嗎，你這個固執鬼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"좋습니다. 저에게는 이게 은퇴전이 되겠군요.","JPN":"いいでしょう。では俺にはこれが引退戦になりますな。","ENG":"That's good with me. Then this shall be my last mission before retiring.","TWN":"明白了。對我來說，這就是退休戰了吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"반드시, 반드시 임무를 성공시키겠습니다. 기관장님.","JPN":"必ず、必ず任務を成功させます。機関長。","ENG":"I give you my word, Chief. I will not fail.","TWN":"我一定，會讓任務成功的，機關長。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"오래된 목소리의 첩보에 따르면, 제임스의 목표는 <color=#ffd34c>성배</color>로 추정됩니다.","JPN":"古い声の諜報によりますと、ジェームスの目標は<color=#ffd34c>聖杯</color>と推測されます。","ENG":"According to the intel from the Old Voice, we predict that the <color=#ffd34c>Holy Grail</color> is what James is after.","TWN":"老聲音給我們的情報表明，詹姆斯的目標是<color=#ffd34c>聖杯</color>。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"성배라고? 말만 들으면 무슨 엄청난 아티팩트 같은데?","JPN":"聖杯？　それだけ聞くと、なんかすごくアーティファクトみたいだな。","ENG":"Holy Grail? Sounds like some powerful Artifact.","TWN":"聖杯？光是聽著就感覺是個了不起的人造神器呢？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"전설에 따르면, 성배란…… 신의 피를 담는 <color=#ffd34c>그릇</color>.","JPN":"伝説によりますと、聖杯は……神の血を宿す<color=#ffd34c>器</color>。","ENG":"According to legend, the Holy Grail... is a <color=#ffd34c>vessel</color> that can carry the blood of god.","TWN":"根據傳說，聖杯……是盛裝神血的<color=#ffd34c>器皿</color>。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"소유주에게 행운을 부여한다든가, 상처를 낫게 한다든가, 영생을 누린다든가…….","JPN":"持ち主に幸運を与えるとか、傷を治すとか、不老不死するとか……","ENG":"Bringing good fortune to the owner, healing injuries, granting immortal life...","TWN":"要麼給持有者帶來幸運，要麼治癒傷口，要麼使其享受永生……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그런 효과들은 전설이 계승되며 후세에 살이 덧붙여진 것뿐입니다.","JPN":"そのような話は伝説が継承されるうちに後から付け足されていったのです。","ENG":"Those effects were added later on as the legend was passed down.","TWN":"這些效果只是傳說被散播的時候，後人的添油加醋而已。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"따라서 성배가 아티팩트라는 보장은 어디에도 없어요.","JPN":"よって、聖杯がアーティファクトだという保証はどこにもありませんわ。","ENG":"Therefore, there is no guarantee that the Holy Grail is an Artifact.","TWN":"因此，並不能保證聖杯就是人造神器。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"실존하는 물건인지, 어떠한 개념인지, 단순한 소문에 불과한지……. ","JPN":"実存しているのか、どのような概念なのか、単なる神話に過ぎないのか…… ","ENG":"It could be an existing object, an idea, or just a rumor...","TWN":"到底是實際存在的東西，是什麼概念，還是說只是單純的傳聞……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"어쩌면 그저 비유이거나, 상징일 지도 모르죠.","JPN":"もしかしたら何かの例えや、象徴なのかもしれません。","ENG":"Or perhaps a metaphor or a symbol.","TWN":"說不定只是一個比喻，或者一個象徵。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 결국 아무것도 모른다는 말이잖아. 꼭 그렇게 말을 어렵게 해야겠어?","JPN":"じゃあ、結局何もわかってないってことじゃないか。そんなに難しく言う必要ないだろ？","ENG":"So you have no idea what it is. You could've started with that.","TWN":"說到底就是你不知道嘛，非得把話說得那麼難嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"무지한 발언이군요, 물벼룩.","JPN":"無知な発言ですわね、ミジンコ。","ENG":"How ignorant of you, Water Flea.","TWN":"真是無知的發言，水蚤。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"프리드웬 기관은 설립 초창기, 아니 그 이전부터 줄곧 성배를 탐색해왔습니다.","JPN":"プリドウェン機関は設立初期、いいえ、その以前からずっと聖杯を探してきました。","ENG":"Prydwen Institution has been searching for the Holy Grail since it was established, or even before that.","TWN":"普利多溫機關成立初期，不，在那之前就一直在探索聖杯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"행운의 편지, 뿔 피리, 소원 구슬, 원숭이 손, 깜짝 상자, 황금 램프.","JPN":"幸運の手紙、角笛、願いの玉、サルの手、ドッキリ箱、黄金のランプ。","ENG":"A chain letter, a horn, a wishing marble, a monkey's paw, a surprise box, a golden lamp.","TWN":"幸運信，角笛，願望寶珠，猴子手，驚喜箱子，黃金燈。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"수없이 많은 성배 후보 아티팩트가 기관과 성황청의 교차검증을 통과하지 못해서 성배가 되지 못했어요.","JPN":"数多くの聖杯候補であるアーティファクトが、機関と聖皇庁のクロス検証をパスできず聖杯なることに失敗してきました。","ENG":"Countless Artifacts that were suspected to be the Holy Grail could not pass the cross-validation conducted by the Institution and the Holy Curia, and therefore could not be the Holy Grail.","TWN":"無數個候選人造神器沒有通過機關和聖皇廳的交叉驗證，所以沒能成為聖杯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"즉, 성배라는 분야에서 기관은 성황청과 동등한 권위를 가진다고 할 수 있죠.","JPN":"つまり、聖杯という分野で機関は聖皇庁と同等の権限を持っていると言えるのです。","ENG":"In other words, the Institution holds equal power to the Holy Curia in matters concerning the Holy Grail.","TWN":"也就是說，在聖杯這個領域中，機關與聖皇廳具有同等的權威。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"교수는 성황청에서 발견한 파편을 두고 버넷 경과 겨루었다고 증언했어요.","JPN":"教授は聖皇庁で発見された破片をめぐって、バーネット卿と戦ったと証言しました。","ENG":"The Professor testified that he fought with Sir Burnett for the Fragment that Holy Curia found.","TWN":"教授作證說，他圍繞在聖皇廳中發現的碎片與伯內特卿進行了較量。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"오래된 목소리는 성배를 찾아서 봉인하라고 조언했습니다.","JPN":"古い声には聖杯を探して封印するようにと助言されました。","ENG":"The Old Voice advised me to find the Holy Grail and to seal it.","TWN":"而老聲音建議我們找到聖杯，並將其封印。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"성배와 파편…….","JPN":"聖杯と破片……","ENG":"The Holy Grail and the Fragment...","TWN":"聖杯和碎片……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"현 시점에서 그 두 가지가 같을 것이라고 단정짓는 것은 위험한 결론이지만.","JPN":"現時点でその二つが同じものだと断定するのは危険ですが……","ENG":"As of now, it would be dangerous to assume that those two are the same thing.","TWN":"雖然目前斷定兩者相同是很危險的結論。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"양쪽 모두 기관에서 오랫동안 추구해온 목표인 이상, 반드시 연결점이 있을 겁니다.","JPN":"二つとも、機関が長らく追ってきた標的である以上、必ず何か繋がりがあるはずですわ。","ENG":"But since they are both objectives that the Institution has been seeking for a long time, there must be a connection.","TWN":"但既然雙方都是機關長期追求的目標，那麼一定會有連接點。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 마음에 안 드네.","JPN":"ったく。気に入らないな。","ENG":"Blimey. That's annoying.","TWN":"真是令人討厭啊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"오래된 목소리인지, 뭔지 하는 녀석은 항상 어정쩡하게 조언을 해주는 거야?","JPN":"古い声とかなんとか、あいつはいつもそんな中途半端な助言をしてるのか？","ENG":"Does that Old Voice or whatever always give you vague advice?","TWN":"這個叫老聲音還什麼的傢伙，為什麼總是提些模棱兩可的建議？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하. 간만에 옳은 말을 하는 군.","JPN":"はは。久しぶりにもっともなことを言うな。","ENG":"Hah hah. For once, I agree with you.","TWN":"呵呵，難得聽到你有正確發言呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐, 어렵게 생각할 거 있어?","JPN":"まあ、難しく考えることはない。","ENG":"Well, it's not that complicated, is it?","TWN":"這有什麼難的？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"교수가 노리는 게 파편이든, 성배든 어쨌든 우리 쪽에서 먼저 회수하면 그만이잖아.","JPN":"教授が狙うのが破片でも聖杯でも、こっちが先に回収すればいい話だ。","ENG":"Whether it's the Fragment or the Holy Grail that the Professor is after, we can just claim it before him.","TWN":"教授盯上的不管是碎片還是聖杯，反正我們先收回不就行了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"겸사겸사 교수도 다시 감방에 집어넣고.","JPN":"そのついでに教授もまた監獄に入れてさ。","ENG":"And put the Professor in prison in the process.","TWN":"順便把教授也抓回牢房。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"말처럼 쉬운 일은 아닐 겁니다, 물벼룩.","JPN":"そう簡単にいくとは思えませんわ、ミジンコ。","ENG":"It will be easier said than done, Water Flea.","TWN":"並不會像你說的那麼容易，水蚤。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제임스의 증언에 따르면, 결국 그 버넷 경조차 임무에 실패한 모양이니까요.","JPN":"ジェームスの証言によると、あのバーネット卿さえ任務に失敗したそうですから。","ENG":"According to James' testimony, even the great Sir Burnett failed the mission.","TWN":"根據詹姆斯的證言，連伯內特卿最終都沒有完成任務。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"성배 탐색이라…….","JPN":"聖杯の探索か……","ENG":"A search for the Holy Grail...","TWN":"探索聖杯……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"좋습니다. 늙은이의 마지막 임무로서는 손색이 없군요.","JPN":"良いでしょう。老人の最後の任務に相応しい。","ENG":"Not bad. It's quite fitting as the last mission for this old man.","TWN":"好吧，作為我這老頭的最後任務確實毫不遜色。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"출발하지, 버넷 요원.","JPN":"出発しよう、エージェント・バーネット。","ENG":"Let's go, Agent Burnett.","TWN":"出發吧，伯內特特工。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네에게 내 등 뒤를 부탁하겠네.","JPN":"君に俺の背中を預けるとしよう。","ENG":"I trust you'll have my back?","TWN":"我的性命就交給你了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 차라리 평소처럼 애송이라고 부르라고. 귀가 간질거리잖아.","JPN":"ったく。いっそ普段みたいに小僧って呼べよ。気持ちわりぃ。","ENG":"Blimey. Just call me kid, like you normally do. I'm getting goosebumps.","TWN":"真是的，還是像平時一樣叫我小鬼吧，耳朵怪癢的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐, 나중에 후회나 하지 마셔.","JPN":"後で後悔するなよ。","ENG":"Well, just don't regret it later.","TWN":"等下？你可不要後悔？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아마 이번에 늙다리가 나설 차례는 없을 테니까 말이야.","JPN":"たぶん次はもう、ジジイの出番はないだろうからな。","ENG":"Because I don't think you'll have a chance to step up this time, old man.","TWN":"我也去恐怕就輪不到老頭你出馬了？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};